from sympy import isprime, nextprime
terms, x = {}, 3
while len(terms) < 7: # program is slow for a(8) and beyond
    y = x
    steps = 0
    while y > 0 and isprime(y):
        steps += 1
        if y % 4 == 1:
            y = (y+1)//2
        elif y % 4 == 3:
            y = (y-1)//2
    if steps not in terms:
        terms[steps] = x
    x = nextprime(x)
for z in terms:
    print(terms[z], end=", ")

